const express = require('express');
const multer = require('multer');
const libxmljs = require('libxmljs');
const xml2js = require('xml2js');

const app = express();

// Set up multer for file uploads
const upload = multer({ dest: 'uploads/' });

app.post('/parse-xml', upload.single('file'), (req, res) => {
  // Parse the uploaded XML using libxmljs
  const xmlDoc = libxmljs.parseXmlString(req.file.buffer);

  // Extract the configuration settings from the XML document
  const configSettings = extractConfigSettings(xmlDoc);

  // Return the configuration settings as a JSON object
  res.json(configSettings);
});

function extractConfigSettings(xmlDoc) {
  // Use xml2js to convert the XML document into a JavaScript object
  const jsonObj = xml2js.parseStringSync(xmlDoc.toString());

  // Extract the configuration settings from the JSON object
  const configSettings = {};
  for (const key in jsonObj) {
    if (key === 'config') {
      configSettings[key] = jsonObj[key];
    } else if (jsonObj[key].hasOwnProperty('config')) {
      configSettings[key] = jsonObj[key]['config'];
    }
  }

  return configSettings;
}